#include<cstdio>
#include<algorithm>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
typedef long long LL;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
template<typename T> inline void chkmax(T&x,const T&w){x<w?x=w:T();}
template<typename T> inline void chkmin(T&x,const T&w){w<x?x=w:T();}
const int N=4e5+10;int n,m,buf[5][N],*a[5];
namespace Sub1{inline LL mian(){LL sm=0;rep(1,n,i)sm+=4ll*n*a[1][i];return sm;}}
namespace Sub2{inline LL mian(){LL Sm=0;rep(1,n,i)Sm+=2ll*n*(a[1][i]+a[2][i]);return Sm;}}
namespace Sub3
{
	int A[N],B[N],C[N],T[N<<1],cnt[N];LL ans;
	struct node{int a,b,idx;} t[N<<1];int P[N<<1],pp;
	inline int bnd(const int &k){int l(1),r(pp),m;while(l<=r)P[m=(l+r)>>1]<=k?l=m+1:r=m-1;return l-1;}
	inline bool cmp(const node&x,const node&y){return x.a==y.a?(x.b==y.b?x.idx<y.idx:x.b<y.b):x.a<y.a;}
	inline void add(int p){while(p<=pp)++T[p],p+=(p&-p);}
	inline int qry(int p) {int r(0);while(p)r+=T[p],p^=(p&-p);return r;}
	inline void getP()
	{
		rep(1,2*n,i)P[i]=t[i].b;std::sort(P+1,P+2*n+1);
		pp=std::unique(P+1,P+2*n+1)-P-1; rep(1,2*n,i)t[i].b=bnd(t[i].b);
	}
	inline void Cnt()
	{
		memset(T,0,(pp+5)*sizeof(int));
		memset(cnt,0,(n+5)*sizeof(int));
		std::sort(t+1,t+2*n+1,cmp); getP();
		rep(1,2*n,i)if(!t[i].idx)add(t[i].b); else cnt[t[i].idx]+=qry(t[i].b);
	}
	inline void Solve()
	{
		rep(1,n,i)
		{
			t[i+n].a=-(t[i].a=B[i]-A[i]);
			t[i+n].b=-(t[i].b=C[i]-A[i]);
			t[i].idx=0;t[i+n].idx=i;
		}
		Cnt();rep(1,n,i)ans+=1ll*cnt[i]*A[i];
		rep(1,n,i)
		{
			t[i+n].a=-(t[i].a=A[i]-B[i])-1;
			t[i+n].b=-(t[i].b=C[i]-B[i]);
			t[i].idx=0;t[i+n].idx=i;
		}
		Cnt();rep(1,n,i)ans+=1ll*cnt[i]*B[i];
		rep(1,n,i)
		{
			t[i+n].a=-(t[i].a=A[i]-C[i])-1;
			t[i+n].b=-(t[i].b=B[i]-C[i])-1;
			t[i].idx=0;t[i+n].idx=i;
		}
		Cnt();rep(1,n,i)ans+=1ll*cnt[i]*C[i]; 
	}
	inline LL mian()
	{
		ans=0;
		memcpy(A,a[1],(n+5)*sizeof(int));
		memcpy(B,a[2],(n+5)*sizeof(int));
		memcpy(C,a[3],(n+5)*sizeof(int));
		Solve(); rep(1,n,i)A[i]=-A[i],B[i]=-B[i],C[i]=-C[i];
		ans=-ans; Solve(); ans=-ans; return ans<<1;
	}
}
namespace Sub4
{
	inline LL mian()
	{
		LL ans=0;rep(1,4,i)
		{
			int tmp=0;rep(1,4,j)if(i!=j)a[++tmp]=buf[j];
			ans+=Sub3::mian();
		}
		rep(1,4,i)rep(1,n,j)ans-=a[i][j];return ans>>1;
	}
}
int main()
{
//	FIN("data.in");//FOUT("mine.out");
	a[1]=buf[1];a[2]=buf[2];a[3]=buf[3];a[4]=buf[4];
	m=read();n=read();rep(1,m,i)rep(1,n,j)buf[i][j]=read();
	if(m==2)return printf("%lld\n",Sub2::mian()),0;
	if(m==3)return printf("%lld\n",Sub3::mian()),0;
	if(m==4)return printf("%lld\n",Sub4::mian()),0;
}
